            return false
        }
        if lhs.deviceModel != rhs.deviceModel {
            return false
        }
        if lhs.deviceType != rhs.deviceType {
            return false
        }
        if lhs.fingerprint != rhs.fingerprint {
            return false
        }
        if lhs.port != rhs.port {
            return false
        }
        if lhs.`protocol` != rhs.`protocol` {
            return false
        }
        if lhs.download != rhs.download {
            return false
        }
