public struct RegisterDto {
    public var alias: String
    public var version: String
    public var deviceModel: String?
    public var deviceType: DeviceType?
    public var fingerprint: String
    public var port: UInt16
    public var `protocol`: ProtocolType
    public var download: Bool

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(alias: String, version: String, deviceModel: String?, deviceType: DeviceType?, fingerprint: String, port: UInt16, `protocol`: ProtocolType, download: Bool) {
        self.alias = alias
        self.version = version
        self.deviceModel = deviceModel
        self.deviceType = deviceType
        self.fingerprint = fingerprint
        self.port = port
        self.`protocol` = `protocol`
        self.download = download
    }
}

#if compiler(>=6)
extension RegisterDto: Sendable {}
#endif


extension RegisterDto: Equatable, Hashable {
    public static func ==(lhs: RegisterDto, rhs: RegisterDto) -> Bool {
        if lhs.alias != rhs.alias {
            return false
        }
        if lhs.version != rhs.version {
            return false
        }
        if lhs.deviceModel != rhs.deviceModel {
            return false
        }
        if lhs.deviceType != rhs.deviceType {
            return false
        }
        if lhs.fingerprint != rhs.fingerprint {
            return false
        }
        if lhs.port != rhs.port {
            return false
        }
        if lhs.`protocol` != rhs.`protocol` {
            return false
        }
        if lhs.download != rhs.download {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(alias)
        hasher.combine(version)
        hasher.combine(deviceModel)
        hasher.combine(deviceType)
        hasher.combine(fingerprint)
        hasher.combine(port)
        hasher.combine(`protocol`)
        hasher.combine(download)
    }
}



